module binary_counter
    (
        input clk,
        input enable,
        input rst,
        output reg [3:0] count
    );

    reg [3:0] obf_count_reg;

    always @(posedge clk) begin
        if (rst) begin
            obf_count_reg <= 4'b0000;
        end else if (enable) begin
            obf_count_reg <= obf_count_reg + 1;
        end
    end

    assign count = obf_count_reg;

endmodule
